  let name = localStorage.getItem("fullname");
  if(name  == null)
   return (<UserModule/>)
  else{
    return (
          <Link to="/edituser">  <i class="fa-regular fa-pen-to-square" ></i> </Link> 
    )
  }

}

export default App;
